func solve(s string, order []int64, k int64) int64 {
    n := len(s)
    replaced := make([]bool, n)
    totalValid := 0

    starPositions := []int{}
    for i := 0; i < n; i++ {
        if s[i] == '*' {
            starPositions = append(starPositions, i)
        }
    }

    countValidSubstrings := func() {
        totalValid = 0
        m := len(starPositions)
        for i := 0; i < m; i++ {
            left := starPositions[i]
            right := starPositions[i]
            for l := left; l >= 0; l-- {
                if replaced[l] {
                    break
                }
                for r := right; r < n; r++ {
                    if replaced[r] {
                        break
                    }
                    totalValid++
                }
            }
            right = starPositions[i] + 1
        }
    }

    left, right := 0, n
    answer := -1
    for left <= right {
        mid := (left + right) / 2
        replaced = make([]bool, n)
        for i := 0; i < mid; i++ {
            replaced[order[i]] = true
        }
        countValidSubstrings()
        if int64(totalValid) >= k {
            answer = mid
            right = mid - 1
        } else {
            left = mid + 1
        }
    }
    return int64(answer)
}
